INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (4, 1, "", 1, 1034501040, 0, 1034501, 103411, 11, 0, "わあ……素敵なケーキね！\nえ？　キミが作ったの？\nすごいじゃない！");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1034501041, "", 1034501, 0, 91, "", "");
