INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (6, 1, "", 1, 1034501043, 0, 1034501, 103411, 11, 0, "麦しゅわに合わないかも……って、\nそんな気を使わなくていいわよ。\nだって、今日は飲むつもりはないもの。");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1034501044, "", 1034501, 0, 91, "", "");
