INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (6, 1, "", 1, 1052501040, 0, 1052501, 105211, 11, 0, "素敵なケーキをありがとう！\nまさかこんな盛大に\nお祝いしてもらえるなんて\n思わなかったわ！");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1052501041, "", 1052501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1052501042, "", 1052501, "vo_adv_1052501", 21, "", "vo_adv_1052501_001");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (6, 1, "", 1, 1052501043, 0, 1052501, 105211, 11, 0, "おめでとうって言ってもらえるだけでも\nうれしいのに、手作りのケーキまで……\n私、あなたにいろんなものを\nもらってばっかりね。");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1052501044, "", 1052501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1052501045, "", 1052501, "vo_adv_1052501", 21, "", "vo_adv_1052501_002");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (5, 1, "", 1, 1052501046, 0, 1052501, 105211, 11, 0, "少しでもお返ししたいけど……\nあなたは何かしてほしいことはある？\nえ？　私の誕生日だから私が\n喜んでくれたらうれしい……？");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1052501047, "", 1052501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1052501048, "", 1052501, "vo_adv_1052501", 21, "", "vo_adv_1052501_003");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (5, 1, "", 1, 1052501049, 0, 1052501, 105211, 11, 0, "私、もう十分に喜んでるわ！\nでも、あなたのそんな言葉を聞いたら\nもう少しわがままを\n言いたくなっちゃうわ。");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1052501050, "", 1052501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1052501051, "", 1052501, "vo_adv_1052501", 21, "", "vo_adv_1052501_004");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (4, 1, "", 1, 1052501052, 0, 1052501, 105211, 11, 0, "ケーキをあーんしてもらってもいい？\n一口だけ、一口だけでいいから！\nいいの？　ありがとう！\n最高の誕生日だわ！");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1052501053, "", 1052501, 0, 91, "", "");
