INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1057501039, "", 1057501, 105711, 13, "", 870);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (6, 1, "", 1, 1057501040, 0, 1057501, 105711, 11, 0, "お祝いしてくれてありがとう！\n私の誕生日、覚えててくれたんだね。\nすごくうれしいな。");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1057501041, "", 1057501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1057501042, "", 1057501, "vo_adv_1057501", 21, "", "vo_adv_1057501_001");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (5, 1, "", 1, 1057501043, 0, 1057501, 105711, 11, 0, "このケーキ、すごく美味しそうだね。\n有名なお店のケーキなのかな？\nえ？　あなたが自分で作ってくれたの？\nすごーい！");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1057501044, "", 1057501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1057501045, "", 1057501, "vo_adv_1057501", 21, "", "vo_adv_1057501_002");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (7, 1, "", 1, 1057501046, 0, 1057501, 105711, 11, 0, "なんだかやる気が出てきちゃった！\nもしよかったら、このあと一緒に\n依頼を受けにいこうよ！");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1057501047, "", 1057501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1057501048, "", 1057501, "vo_adv_1057501", 21, "", "vo_adv_1057501_003");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (5, 1, "", 1, 1057501049, 0, 1057501, 105711, 11, 0, "ゆっくりでいいからがんばって\n騎空団として成長して……\nいつかは蒼い空を自由に旅したいな。\nもちろん、その時はあなたも一緒だよ！");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1057501050, "", 1057501, 0, 91, "", "");
