INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (4, 1, "", 1, 1070501040, 0, 1070501, 107011, 11, 0, "ふむ、よい趣向ですね。\n敬うべき相手を忘れず、恩を忘れず、\n健勝を祝う宴を開く……\n礼節を弁えた人間は好きですよ。");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1070501041, "", 1070501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1070501042, "", 1070501, "vo_adv_1070501", 21, "", "vo_adv_1070501_001");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (5, 1, "", 1, 1070501043, 0, 1070501, 107011, 11, 0, "しかし一時には\n赤子同然だった貴方が\nここまで成長したこと……\nとても喜ばしく思います。");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1070501044, "", 1070501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1070501045, "", 1070501, "vo_adv_1070501", 21, "", "vo_adv_1070501_002");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (5, 1, "", 1, 1070501046, 0, 1070501, 107011, 11, 0, "ただ、そうですね……\n厚意に預かるばかり、\nというのも性に合いませんし。\n何かご褒美をあげましょう。");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1070501047, "", 1070501, 0, 91, "", "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (0, 0, "", "", 1070501048, "", 1070501, "vo_adv_1070501", 21, "", "vo_adv_1070501_003");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES (5, 1, "", 1, 1070501049, 0, 1070501, 107011, 11, 0, "焦って決めずとも構いません。\n今日は一日、私が飽きるまで\n貴方に付き合ってもらう予定ですから。\nふふ……期待していますよ？");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 1070501050, "", 1070501, 0, 91, "", "");
